dtsPropsFor.Button:
/** Visual style. One primary (`default`) per view. @default "default" */
variant?: "default" | "destructive" | "outline" | "secondary" | "ghost" | "link";
/** Size preset. `icon*` sizes render a square button for a lone icon. @default "default" */
size?: "default" | "sm" | "lg" | "icon" | "icon-sm" | "icon-lg";
/** Render as the single child element (Radix Slot) instead of a <button>. @default false */
asChild?: boolean;
disabled?: boolean;
type?: "button" | "submit" | "reset";
onClick?: React.MouseEventHandler<HTMLButtonElement>;
className?: string;
children?: React.ReactNode;
/** Plus all native <button> attributes. */
[prop: `data-${string}`]: unknown;

dtsPropsFor.Input:
/** Input type. @default "text" */
type?: React.HTMLInputTypeAttribute;
value?: string | number;
defaultValue?: string | number;
placeholder?: string;
disabled?: boolean;
onChange?: React.ChangeEventHandler<HTMLInputElement>;
className?: string;
/** Plus all native <input> attributes (name, required, min, max, …). */
[prop: `data-${string}`]: unknown;

dtsPropsFor.Checkbox:
/** Controlled checked state. `"indeterminate"` shows the mixed state. */
checked?: boolean | "indeterminate";
defaultChecked?: boolean;
onCheckedChange?: (checked: boolean | "indeterminate") => void;
disabled?: boolean;
required?: boolean;
name?: string;
value?: string;
className?: string;

dtsPropsFor.Slider:
/** Controlled value (array — one entry per thumb). */
value?: number[];
defaultValue?: number[];
onValueChange?: (value: number[]) => void;
onValueCommit?: (value: number[]) => void;
/** @default 0 */
min?: number;
/** @default 100 */
max?: number;
/** @default 1 */
step?: number;
orientation?: "horizontal" | "vertical";
disabled?: boolean;
"aria-label"?: string;
className?: string;

dtsPropsFor.Alert:
/** `destructive` tints the title/description with the danger token. @default "default" */
variant?: "default" | "destructive";
/** Compose an optional lucide icon, <AlertTitle>, and <AlertDescription> as children. */
children?: React.ReactNode;
className?: string;
/** Plus all native <div> attributes. */
[prop: `data-${string}`]: unknown;

dtsPropsFor.Dialog:
/** Controlled open state. */
open?: boolean;
defaultOpen?: boolean;
onOpenChange?: (open: boolean) => void;
/** Trap focus + block the background while open. @default true */
modal?: boolean;
/** Compose <DialogTrigger>, <DialogContent> (which holds <DialogHeader> → <DialogTitle> + <DialogDescription>, body, <DialogFooter>, <DialogClose>). */
children?: React.ReactNode;

dtsPropsFor.DropdownMenu:
/** Controlled open state. */
open?: boolean;
defaultOpen?: boolean;
onOpenChange?: (open: boolean) => void;
modal?: boolean;
dir?: "ltr" | "rtl";
/** Compose <DropdownMenuTrigger> + <DropdownMenuContent> holding <DropdownMenuItem>, <DropdownMenuCheckboxItem>, <DropdownMenuRadioGroup>/<DropdownMenuRadioItem>, <DropdownMenuLabel>, <DropdownMenuSeparator>, <DropdownMenuSub>. */
children?: React.ReactNode;

dtsPropsFor.Popover:
/** Controlled open state. */
open?: boolean;
defaultOpen?: boolean;
onOpenChange?: (open: boolean) => void;
modal?: boolean;
/** Compose <PopoverTrigger> + <PopoverContent> (optionally <PopoverAnchor>). */
children?: React.ReactNode;

dtsPropsFor.Select:
/** Controlled selected value. */
value?: string;
defaultValue?: string;
onValueChange?: (value: string) => void;
open?: boolean;
defaultOpen?: boolean;
onOpenChange?: (open: boolean) => void;
disabled?: boolean;
required?: boolean;
name?: string;
dir?: "ltr" | "rtl";
/** Compose <SelectTrigger> (holding <SelectValue>) + <SelectContent> holding <SelectItem>, <SelectGroup>/<SelectLabel>, <SelectSeparator>. */
children?: React.ReactNode;

dtsPropsFor.Tooltip:
/** Controlled open state. */
open?: boolean;
defaultOpen?: boolean;
onOpenChange?: (open: boolean) => void;
/** Delay in ms before the tooltip opens on hover. */
delayDuration?: number;
disableHoverableContent?: boolean;
/** Compose <TooltipTrigger> + <TooltipContent>. Wrap the app (or the tooltip) in <TooltipProvider>. */
children?: React.ReactNode;

dtsPropsFor.ScrollArea:
/** When scrollbars show. @default "hover" */
type?: "auto" | "always" | "scroll" | "hover";
/** Delay in ms before hover/scroll scrollbars hide. */
scrollHideDelay?: number;
dir?: "ltr" | "rtl";
/** The scrollable content. Pair with <ScrollBar> for a horizontal bar. */
children?: React.ReactNode;
className?: string;

dtsPropsFor.Toaster:
/** Screen corner for the toast stack. @default "bottom-right" */
position?: "top-left" | "top-center" | "top-right" | "bottom-left" | "bottom-center" | "bottom-right";
/** Auto-dismiss delay in ms. */
duration?: number;
/** Show a close button on each toast. */
closeButton?: boolean;
/** Stack expanded instead of collapsed. */
expand?: boolean;
richColors?: boolean;
className?: string;
/** Mount once near the app root; fire toasts imperatively via sonner's `toast()`. Dark-themed, Manabase-tokened, with success/info/warning/error/loading icons preset. */
[prop: `data-${string}`]: unknown;

dtsPropsFor.HudIconButton:
/** The icon element (e.g. a lucide <SettingsIcon />). */
icon: React.ReactNode;
/** Accessible label (also the default title). */
ariaLabel: string;
onClick: () => void;
title?: string;
/** For toggle buttons: whether the surface this button controls is open. */
ariaExpanded?: boolean;
testId?: string;

dtsPropsFor.FloatingPanel:
/** Stable key for saving/restoring this panel's viewport position. */
persistKey: string;
/** Where the panel first appears if nothing is persisted yet. */
defaultPosition: { x: number; y: number };
/** Label shown in the built-in grip handle. Ignored when `renderHandle` is set. */
title?: string;
/** Render a custom drag handle instead of the built-in grip. Must spread the given handle props onto its root and set `touchAction: 'none'`. */
renderHandle?: (handleProps: React.HTMLAttributes<HTMLElement>) => React.ReactNode;
/** Fixed panel width. Omit to size to content. */
width?: number | string;
/** @default 40 */
zIndex?: number;
children: React.ReactNode;
